from pydantic import BaseModel, Field, field_validator
from typing import Optional
import json

class FlightSearchArgs(BaseModel):
    origin: str = Field(description="IATA code, uppercase.")
    destination: str = Field(description="IATA code, uppercase.")
    date: str = Field(description="YYYY-MM-DD.")
    cabin_class: str = Field(default="economy")

    @field_validator("origin", "destination")
    @classmethod
    def uppercase_iata(cls, v: str) -> str:
        return v.upper().strip()

    @field_validator("cabin_class")
    @classmethod
    def normalize_cabin(cls, v: str) -> str:
        return v.lower().strip()

raw = '{"origin": "lhr", "destination": "nrt", "date": "2025-07-15", "cabin_class": "Business"}'
args = FlightSearchArgs.model_validate_json(raw)
print(args.origin)        # "LHR"
print(args.cabin_class)   # "business"

from openai import OpenAI
from langchain_core.messages import HumanMessage, ToolMessage
import json

client = OpenAI()

tools = [search_tool, summarize_tool, email_tool]
tool_map = {
    "search_documents": search_documents,
    "summarize_text": summarize_text,
    "send_email": send_email,
}

def run_agent(user_message: str) -> str:
    messages = [{"role": "user", "content": user_message}]

    while True:
        response = client.chat.completions.create(
            model="gpt-4o-mini",
            messages=messages,
            tools=tools,
            tool_choice="auto",
        )

        choice = response.choices[0]
        messages.append(choice.message)   # always append assistant turn

        if choice.finish_reason == "stop":
            return choice.message.content

        # Execute all tool calls; LLM will use results to construct next args
        for tc in choice.message.tool_calls:
            args = json.loads(tc.function.arguments)
            result = tool_map[tc.function.name](**args)
            messages.append({
                "role": "tool",
                "tool_call_id": tc.id,
                "content": json.dumps(result),
            })

# The LLM:
# 1. Calls search_documents with {"query": "Q3 earnings Apple", "top_k": 3}
# 2. Reads results; calls summarize_text with {"text": "<search results>"}
# 3. Reads summary; calls send_email with {"to": "...", "subject": "...", "body": "<summary>"}
run_agent("Find the Q3 Apple earnings report, summarize it, and email it to alice@example.com")

import json
import logging

logger = logging.getLogger(__name__)

def dispatch_tool_call(tool_call):
    raw_args = tool_call.function.arguments
    logger.debug(
        "Tool call: name=%s raw_args=%s",
        tool_call.function.name,
        raw_args,
    )

    try:
        args = json.loads(raw_args)
    except json.JSONDecodeError as e:
        logger.error("Invalid JSON in tool call: %s — raw: %s", e, raw_args)
        return {"error": "Malformed arguments from LLM"}

    # Validate with Pydantic or jsonschema here
    return execute_tool(tool_call.function.name, args)
